drop extension if exists "pg_net";

create sequence "public"."games_id_seq";

create sequence "public"."grounds_id_seq";

create sequence "public"."leagues_id_seq";

create sequence "public"."players_id_seq";

create sequence "public"."vsteams_id_seq";


  create table "public"."at_bat_results" (
    "no" bigint generated by default as identity not null,
    "name" character varying,
    "short_name" character varying,
    "display_name" character varying,
    "create_at" timestamp without time zone not null default now(),
    "is_at_bat" boolean,
    "bases" smallint,
    "outs" smallint,
    "with_direction" boolean
      );


alter table "public"."at_bat_results" enable row level security;


  create table "public"."attendance" (
    "team_id" character varying not null,
    "game_id" character varying not null,
    "player_id" character varying not null,
    "attendance_no" smallint,
    "real_attendance_no" smallint,
    "comment" text,
    "helper_count" smallint,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."attendance" enable row level security;


  create table "public"."batting_result_details" (
    "team_id" character varying not null,
    "game_id" character varying not null,
    "player_id" character varying not null,
    "inning_index" smallint not null,
    "at_bat_result_no" smallint,
    "direction_no" smallint,
    "rbi" smallint,
    "create_at" timestamp with time zone default now(),
    "inning" smallint,
    "batting_index" smallint not null
      );


alter table "public"."batting_result_details" enable row level security;


  create table "public"."batting_results" (
    "team_id" character varying not null,
    "game_id" character varying not null,
    "player_id" character varying not null,
    "batting_order" smallint not null,
    "steal" smallint default '0'::smallint,
    "run" smallint default '0'::smallint,
    "df_error" smallint default '0'::smallint,
    "steal_miss" smallint default '0'::smallint,
    "created_at" timestamp with time zone not null default now(),
    "positions" smallint[],
    "batting_index" smallint not null
      );


alter table "public"."batting_results" enable row level security;


  create table "public"."games" (
    "team_id" character varying not null,
    "id" character varying not null default nextval('public.games_id_seq'::regclass),
    "start_datetime" timestamp with time zone not null,
    "league_id" character varying,
    "ground_id" character varying,
    "is_batting_first" boolean,
    "vsteam_id" character varying,
    "status" smallint,
    "remarks" text,
    "game_comment" text,
    "created_at" timestamp with time zone not null default now(),
    "sum_flg" boolean not null,
    "top_points" smallint[],
    "bottom_points" smallint[],
    "innings" smallint[],
    "now_inning" smallint,
    "now_is_top" boolean
      );


alter table "public"."games" enable row level security;


  create table "public"."goals" (
    "team_id" character varying not null,
    "player_id" character varying not null,
    "year" smallint not null,
    "goal_no" bigint not null,
    "goal_value" text,
    "memo" text,
    "created_at" timestamp with time zone not null default now(),
