set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.get_my_team_id()
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$SELECT team_id FROM public.players 
  WHERE user_id = auth.uid() 
  LIMIT 1;$function$
;

create materialized view "public"."mv_player_daily_pitching_stats" as  WITH base_stats AS (
         SELECT p.team_id,
            p.player_id,
            g.id AS game_id,
            date(g.start_datetime) AS game_date,
            g.start_datetime,
            (EXTRACT(year FROM g.start_datetime))::integer AS season_year,
            g.league_id,
            l.name AS league_name,
            g.ground_id,
            gr.name AS ground_name,
            g.vsteam_id,
            vs.name AS vsteam_name,
            g.status AS game_status,
            g.sum_flg,
            ((COALESCE((p.innings)::integer, 0) * 3) + COALESCE((p.outs)::integer, 0)) AS outs,
            ((((COALESCE((p.innings)::integer, 0) * 3) + COALESCE((p.outs)::integer, 0)))::numeric / 3.0) AS ip,
            COALESCE((p.hits)::integer, 0) AS h,
            COALESCE((p.walks)::integer, 0) AS bb,
            COALESCE((p.hbp)::integer, 0) AS hbp,
            COALESCE((p.strikeout)::integer, 0) AS so,
            COALESCE((p.runs)::integer, 0) AS er,
            COALESCE((p.homeruns)::integer, 0) AS hr,
                CASE
                    WHEN (p.is_save = true) THEN 1
                    ELSE 0
                END AS sv,
                CASE
                    WHEN (p.is_hold = true) THEN 1
                    ELSE 0
                END AS hld,
                CASE
                    WHEN (g.status = 1) THEN 1
                    ELSE 0
                END AS wins,
                CASE
                    WHEN (g.status = 2) THEN 1
                    ELSE 0
                END AS losses
           FROM (((((public.pitching_results p
             JOIN public.games g ON ((((p.team_id)::text = (g.team_id)::text) AND ((p.game_id)::text = (g.id)::text))))
             JOIN public.players pl ON ((((pl.team_id)::text = (p.team_id)::text) AND ((pl.id)::text = (p.player_id)::text))))
             LEFT JOIN public.leagues l ON ((((l.id)::text = (g.league_id)::text) AND ((l.team_id)::text = (g.team_id)::text))))
             LEFT JOIN public.grounds gr ON ((((gr.id)::text = (g.ground_id)::text) AND ((gr.team_id)::text = (g.team_id)::text))))
             LEFT JOIN public.vsteams vs ON ((((vs.id)::text = (g.vsteam_id)::text) AND ((vs.team_id)::text = (g.team_id)::text))))
          WHERE ((g.sum_flg = true) AND (g.status <> ALL (ARRAY[0, 6])))
        )
 SELECT team_id,
    player_id,
    game_id,
    game_date,
    start_datetime,
    season_year,
    league_id,
    league_name,
    ground_id,
    ground_name,
    vsteam_id,
    vsteam_name,
    game_status,
    sum_flg,
    outs,
    ip,
    h,
    bb,
    hbp,
    so,
    er,
    hr,
    sv,
    hld,
    wins,
    losses,
    sum(outs) OVER w AS cum_outs,
    sum(ip) OVER w AS cum_ip,
    sum(h) OVER w AS cum_h,
    sum(bb) OVER w AS cum_bb,
    sum(so) OVER w AS cum_so,
    sum(er) OVER w AS cum_er,
        CASE
            WHEN (sum(outs) OVER w > 0) THEN round(((((sum(h) OVER w + sum(bb) OVER w))::numeric * 3.0) / (sum(outs) OVER w)::numeric), 3)
            ELSE (0)::numeric
        END AS whip,
        CASE
            WHEN (sum(outs) OVER w > 0) THEN round((((sum(er) OVER w)::numeric * 21.0) / (sum(outs) OVER w)::numeric), 2)
            ELSE 999.99
        END AS era,
        CASE
            WHEN (sum(outs) OVER w > 0) THEN round((((sum(so) OVER w)::numeric * 21.0) / (sum(outs) OVER w)::numeric), 2)
            ELSE (0)::numeric
        END AS k7
   FROM base_stats
  WINDOW w AS (PARTITION BY team_id, player_id ORDER BY start_datetime ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)
  ORDER BY start_datetime DESC, player_id;


create materialized view "public"."mv_player_daily_stats" as  WITH batting_lines AS (
         SELECT d.team_id,
            d.player_id,
            g.id AS game_id,
            date(g.start_datetime) AS game_date,
            g.start_datetime,
            (EXTRACT(year FROM g.start_datetime))::integer AS season_year,
            g.league_id,
            l.name AS league_name,
            g.ground_id,
            gr.name AS ground_name,
            g.vsteam_id,
            vs.name AS vsteam_name,
            g.status AS game_status,
            g.sum_flg,
            count(*) AS pa,
            sum(
                CASE
                    WHEN (r.is_at_bat = true) THEN 1
                    ELSE 0
                END) AS ab,
            sum(
                CASE
                    WHEN (r.no = ANY (ARRAY[4, 5, 6, 7])) THEN 1
                    ELSE 0
                END) AS h,
            sum(
                CASE
                    WHEN (r.no = 5) THEN 1
                    ELSE 0
                END) AS d2,
            sum(
                CASE
                    WHEN (r.no = 6) THEN 1
                    ELSE 0
                END) AS t3,
            sum(
                CASE
                    WHEN (r.no = 7) THEN 1
                    ELSE 0
                END) AS hr,
            COALESCE(sum(r.bases), (0)::bigint) AS tb,
            sum(
                CASE
                    WHEN (r.no = ANY (ARRAY[2, 3])) THEN 1
                    ELSE 0
                END) AS bb_hbp,
            sum(
                CASE
                    WHEN (r.no = 10) THEN 1
                    ELSE 0
                END) AS sf,
            sum(
                CASE
                    WHEN (r.no = 11) THEN 1
                    ELSE 0
                END) AS sh,
            sum(
                CASE
                    WHEN (r.no = 1) THEN 1
                    ELSE 0
                END) AS so,
            sum(d.rbi) AS rbi,
            COALESCE(sum(r.outs), (0)::bigint) AS total_outs
           FROM ((((((public.batting_result_details d
             JOIN public.at_bat_results r ON ((d.at_bat_result_no = r.no)))
             JOIN public.games g ON ((((d.game_id)::text = (g.id)::text) AND ((g.team_id)::text = (d.team_id)::text))))
             JOIN public.players p ON ((((p.team_id)::text = (d.team_id)::text) AND ((p.id)::text = (d.player_id)::text))))
             LEFT JOIN public.leagues l ON ((((l.id)::text = (g.league_id)::text) AND ((l.team_id)::text = (d.team_id)::text))))
             LEFT JOIN public.grounds gr ON ((((gr.id)::text = (g.ground_id)::text) AND ((gr.team_id)::text = (d.team_id)::text))))
             LEFT JOIN public.vsteams vs ON ((((vs.id)::text = (g.vsteam_id)::text) AND ((vs.team_id)::text = (d.team_id)::text))))
          WHERE ((g.sum_flg = true) AND (g.status <> ALL (ARRAY[0, 6])))
          GROUP BY d.team_id, d.player_id, g.id, (date(g.start_datetime)), g.start_datetime, (EXTRACT(year FROM g.start_datetime)), g.league_id, l.name, g.ground_id, gr.name, g.vsteam_id, vs.name, g.status, g.sum_flg
        ), running_stats AS (
         SELECT b.team_id,
            b.player_id,
            b.game_id,
            COALESCE(sum(b.steal), (0)::bigint) AS sb,
            COALESCE(sum(b.steal_miss), (0)::bigint) AS cs,
            COALESCE(sum(b.run), (0)::bigint) AS runs,
            COALESCE(sum(b.df_error), (0)::bigint) AS errors
           FROM public.batting_results b
          GROUP BY b.team_id, b.player_id, b.game_id
        ), attendance_stats AS (
         SELECT a.team_id,
            a.player_id,
            a.game_id,
            max(
                CASE
                    WHEN (a.real_attendance_no = 1) THEN 1
                    ELSE 0
                END) AS attended_game
           FROM public.attendance a
          GROUP BY a.team_id, a.player_id, a.game_id
        ), base_stats AS (
         SELECT bl.team_id,
            bl.player_id,
            bl.game_id,
            bl.game_date,
            bl.start_datetime,
            bl.season_year,
            bl.league_id,
            bl.league_name,
            bl.ground_id,
            bl.ground_name,
            bl.vsteam_id,
            bl.vsteam_name,
            bl.game_status,
            bl.sum_flg,
            bl.pa,
            bl.ab,
            bl.h,
            bl.d2,
            bl.t3,
            bl.hr,
            bl.tb,
            bl.bb_hbp,
            bl.sf,
            bl.sh,
            bl.so,
            bl.rbi,
            bl.total_outs,
            COALESCE(rs.sb, (0)::bigint) AS sb,
            COALESCE(rs.cs, (0)::bigint) AS cs,
            COALESCE(rs.runs, (0)::bigint) AS runs,
            COALESCE(rs.errors, (0)::bigint) AS errors,
            COALESCE(att.attended_game, 0) AS attended_game
           FROM ((batting_lines bl
             LEFT JOIN running_stats rs ON ((((rs.team_id)::text = (bl.team_id)::text) AND ((rs.player_id)::text = (bl.player_id)::text) AND ((rs.game_id)::text = (bl.game_id)::text))))
             LEFT JOIN attendance_stats att ON ((((att.team_id)::text = (bl.team_id)::text) AND ((att.player_id)::text = (bl.player_id)::text) AND ((att.game_id)::text = (bl.game_id)::text))))
        )
 SELECT team_id,
    player_id,
    game_id,
    game_date,
    start_datetime,
    season_year,
    league_id,
    league_name,
    ground_id,
    ground_name,
    vsteam_id,
    vsteam_name,
    game_status,
    sum_flg,
    pa,
    ab,
    h,
    d2,
    t3,
    hr,
    tb,
    bb_hbp,
    sf,
    sh,
    so,
    rbi,
    total_outs,
    sb,
    cs,
    runs,
    errors,
    attended_game,
    sum(pa) OVER w AS cum_pa,
    sum(ab) OVER w AS cum_ab,
    sum(h) OVER w AS cum_h,
    sum(tb) OVER w AS cum_tb,
    sum(bb_hbp) OVER w AS cum_bb_hbp,
    sum(sf) OVER w AS cum_sf,
    round((sum(h) OVER w / NULLIF(sum(ab) OVER w, (0)::numeric)), 3) AS avg,
    round(((sum(h) OVER w + sum(bb_hbp) OVER w) / NULLIF(((sum(ab) OVER w + sum(bb_hbp) OVER w) + sum(sf) OVER w), (0)::numeric)), 3) AS obp,
    round((sum(tb) OVER w / NULLIF(sum(ab) OVER w, (0)::numeric)), 3) AS slg,
    (round(((sum(h) OVER w + sum(bb_hbp) OVER w) / NULLIF(((sum(ab) OVER w + sum(bb_hbp) OVER w) + sum(sf) OVER w), (0)::numeric)), 3) + round((sum(tb) OVER w / NULLIF(sum(ab) OVER w, (0)::numeric)), 3)) AS ops
   FROM base_stats
  WINDOW w AS (PARTITION BY team_id, player_id ORDER BY start_datetime ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)
  ORDER BY start_datetime DESC, player_id;


