CREATE OR REPLACE FUNCTION public.upsert_game_result(p_team_id character varying, p_game_id character varying, p_batting_result jsonb, p_pitching_result jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
    v_batting_record jsonb;    -- 1人分の打者データ
    v_pitching_record jsonb;    -- 1人分の投手データ
BEGIN
    -- 打者成績を削除
    DELETE FROM batting_result_details
    WHERE team_id = p_team_id
    AND game_id = p_game_id
    ;

    DELETE FROM batting_results
    WHERE team_id = p_team_id
    AND game_id = p_game_id
    ;

    -- 打者成績を登録
    FOR v_batting_record IN SELECT * FROM jsonb_array_elements(p_batting_result)
    LOOP
        INSERT INTO batting_results (
            team_id,
            game_id,
            player_id,
            batting_index,
            batting_order,
            positions,
            run,
            steal,
            steal_miss,
            df_error
        ) VALUES (
            (v_batting_record->>'team_id')::VARCHAR,
            (v_batting_record->>'game_id')::VARCHAR,
            (v_batting_record->>'player_id')::VARCHAR,
            (v_batting_record->>'batting_index')::INT,
            (v_batting_record->>'batting_order')::INT,
            (SELECT ARRAY(
                SELECT x::INT 
                FROM jsonb_array_elements_text(v_batting_record->'pisitions') AS x
            )), 
            (v_batting_record->>'run')::INT,
            (v_batting_record->>'steal')::INT,
            (v_batting_record->>'steal_miss')::INT,
            (v_batting_record->>'df_error')::INT
        );

        INSERT INTO batting_result_details (
            team_id,
            game_id,
            player_id,
            batting_index,
            inning,
            inning_index,
            at_bat_result_no,
            direction_no,
            rbi
        )
        SELECT
            (p_team_id)::VARCHAR,
            (p_game_id)::VARCHAR,
            (v_batting_record->>'player_id')::VARCHAR,
            (v_batting_record->>'batting_index')::INT,
            (d->>'inning')::INT,
            (d->>'inning_index')::INT,
            (d->>'at_bat_result_no')::INT,
            (d->>'direction_no')::INT,
            (d->>'rbi')::INT
        FROM jsonb_array_elements(v_batting_record->'batting_result_details') AS d;
    END LOOP;

    -- 投手成績を削除
    DELETE FROM pitching_results
    WHERE team_id = p_team_id
    AND game_id = p_game_id;

    -- 投手成績を登録
    FOR v_pitching_record IN SELECT * FROM jsonb_array_elements(p_pitching_result)
    LOOP
        INSERT INTO pitching_results (
            team_id,
            game_id,
            player_id,
            pitching_order,
            innings,
            outs,
            runs,
            strikeout,
            walks,
            hbp,
            hits,
            homeruns,
            is_win_lose,
            is_hold,
            is_save
        ) VALUES (
            (v_pitching_record->>'team_id')::VARCHAR,
            (v_pitching_record->>'game_id')::VARCHAR,
            (v_pitching_record->>'player_id')::VARCHAR,
            (v_pitching_record->>'pitching_order')::INT,
            (v_pitching_record->>'innings')::INT,
            (v_pitching_record->>'outs')::INT,
            (v_pitching_record->>'runs')::INT,
            (v_pitching_record->>'strikeout')::INT,
            (v_pitching_record->>'walks')::INT,
            (v_pitching_record->>'hbp')::INT,
            (v_pitching_record->>'hits')::INT,
            (v_pitching_record->>'homeruns')::INT,
            (v_pitching_record->>'is_win_lose')::BOOLEAN,
            (v_pitching_record->>'is_hold')::BOOLEAN,
            (v_pitching_record->>'is_save')::BOOLEAN
        );
    END LOOP;
END;$function$
;

